SELECT ?university ?count WHERE {
  VALUES ?university { wd:Q230492 wd:Q309331 }
  ?university wdt:P2522 ?championship.
  SERVICE wikibase:group { ?university ?p ?championship. }
  BIND(COUNT(?championship) AS ?count)
} GROUP BY ?university

SELECT ?university (COUNT(?championship) AS ?count) WHERE {
  VALUES ?university { wd:Q230492 wd:Q309331 }
  ?university wdt:P2522 ?championship.
} GROUP BY ?university

SELECT ?university (COUNT(?award) AS ?count) WHERE {
  VALUES ?university { wd:Q230492 wd:Q309331 }
  ?team wdt:P3451 ?university.
  ?team wdt:P166 ?award.
} GROUP BY ?university

